using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.UI;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        // ---------- LIVE Studio ----------
        private LiveStudioClient _client;

        // ---------- Mission State ----------
        private enum MissionState { Inactive, Active, Win, Fail }
        private MissionState _state = MissionState.Inactive;

        private Vehicle _missionVehicle;
        private Blip _destinationBlip;
        private DateTime _missionStartTime;
        private DateTime _lastMissionEndTime = DateTime.MinValue;
        private bool _inDetour;
        private Vector3 _originalDestination;

        // ---------- Spawned Entities ----------
        private List<Vehicle> _pursuerVehicles = new List<Vehicle>();
        private List<Vehicle> _escortVehicles = new List<Vehicle>();
        private List<Ped> _escortPeds = new List<Ped>();

        // ---------- Effects ----------
        private List<ActiveTimer> _activeTimers = new List<ActiveTimer>();
        private Dictionary<string, DateTime> _lastCommandTimes = new Dictionary<string, DateTime>();

        private static readonly Dictionary<string, double> CommandCooldowns = new Dictionary<string, double>
        {
            {"!repair", 30}, {"!bulletproof", 60}, {"!clearpursuers", 15}, {"!speedboost", 30},
            {"!escort", 90}, {"!puncture", 20}, {"!stall", 25}, {"!pursuers", 45},
            {"!lowtraction", 35}, {"!explosion", 40}, {"!detour", 120}
        };

        // ---------- Constructor ----------
        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        // ---------- Event Handler ----------
        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is ChatEvent chat)
            {
                MainThreadDispatcher.Enqueue(() => ProcessChat(chat.Content));
            }
            // no gift triggers
        }

        // ---------- Chat Processing ----------
        private void ProcessChat(string content)
        {
            if (string.IsNullOrEmpty(content)) return;
            content = content.Trim();
            string lower = content.ToLowerInvariant();

            // Start delivery
            if (_state == MissionState.Inactive && lower == "!startdelivery")
            {
                if ((DateTime.Now - _lastMissionEndTime).TotalSeconds < 5)
                {
                    GTA.UI.Notification.Show("~r~Delivery is on cooldown. Please wait a few seconds.");
                    return;
                }
                StartMission();
                return;
            }

            if (_state != MissionState.Active) return;

            if (!IsCooldownExpired(content)) return;

            switch (lower)
            {
                case "!repair": RepairEffect(); break;
                case "!bulletproof": BulletproofEffect(); break;
                case "!clearpursuers": ClearPursuers(); break;
                case "!speedboost": SpeedBoost(); break;
                case "!escort": EscortEffect(); break;
                case "!puncture": PunctureEffect(); break;
                case "!stall": StallEffect(); break;
                case "!pursuers": PursuersEffect(); break;
                case "!lowtraction": LowTractionEffect(); break;
                case "!explosion": ExplosionEffect(); break;
                case "!detour": DetourEffect(); break;
            }

            RecordCommand(content);
        }

        private bool IsCooldownExpired(string command)
        {
            if (!CommandCooldowns.ContainsKey(command)) return true;
            if (_lastCommandTimes.TryGetValue(command, out DateTime last))
                return (DateTime.Now - last).TotalSeconds >= CommandCooldowns[command];
            return true;
        }

        private void RecordCommand(string command)
        {
            _lastCommandTimes[command] = DateTime.Now;
        }

        // ---------- Mission Methods ----------
        private void StartMission()
        {
            Ped player = Game.Player.Character;
            Vector3 pos = player.Position;
            float heading = player.Heading;

            // Spawn mission vehicle
            _missionVehicle = World.CreateVehicle(VehicleHash.Boxville, pos, heading);
            if (_missionVehicle == null || !_missionVehicle.Exists())
            {
                GTA.UI.Notification.Show("~r~Failed to spawn vehicle.");
                return;
            }
            player.SetIntoVehicle(_missionVehicle, VehicleSeat.Driver);

            // Destination
            _originalDestination = World.GetNextPositionOnStreet(player.Position.Around(1000f));
            _destinationBlip = World.CreateBlip(_originalDestination);
            if (_destinationBlip != null)
            {
                _destinationBlip.Sprite = BlipSprite.Standard;
                _destinationBlip.IsShortRange = false;
                _destinationBlip.ShowRoute = true;
            }

            _state = MissionState.Active;
            _missionStartTime = DateTime.Now;
            _inDetour = false;

            GTA.UI.Notification.Show("~y~Delivery started! 10 minutes to reach the destination.");
        }

        private void MissionFail(string reason)
        {
            GTA.UI.Notification.Show("~r~Mission Failed: " + reason);
            CleanupMission();
            _state = MissionState.Inactive;
            _lastMissionEndTime = DateTime.Now;
        }

        private void MissionWin()
        {
            GTA.UI.Notification.Show("~g~Delivery Complete!");
            CleanupMission();
            _state = MissionState.Inactive;
            _lastMissionEndTime = DateTime.Now;
        }

        private void CleanupMission()
        {
            // Mission vehicle
            if (_missionVehicle != null && _missionVehicle.Exists())
                _missionVehicle.Delete();
            _missionVehicle = null;

            // Pursuers
            foreach (var v in _pursuerVehicles)
                if (v != null && v.Exists()) v.Delete();
            _pursuerVehicles.Clear();

            // Escorts
            foreach (var v in _escortVehicles)
                if (v != null && v.Exists()) v.Delete();
            _escortVehicles.Clear();
            foreach (var p in _escortPeds)
                if (p != null && p.Exists()) p.Delete();
            _escortPeds.Clear();

            // Blip
            if (_destinationBlip != null && _destinationBlip.Exists())
                _destinationBlip.Remove();
            _destinationBlip = null;

            // Timers
            _activeTimers.Clear();
            _lastCommandTimes.Clear();
            _inDetour = false;
        }

        // ---------- Effects ----------
        private void RepairEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            int max = _missionVehicle.MaxHealth;
            _missionVehicle.Health = Math.Min(_missionVehicle.Health + max / 4, max);
            GTA.UI.Notification.Show("~g~+25% Vehicle Repaired");
        }

        private void BulletproofEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            _missionVehicle.CanTiresBurst = false;
            _activeTimers.Add(new ActiveTimer
            {
                StartTime = Game.GameTime,
                Duration = 30000,
                Action = () => { if (_missionVehicle != null && _missionVehicle.Exists()) _missionVehicle.CanTiresBurst = true; }
            });
            GTA.UI.Notification.Show("~b~Bulletproof tires for 30s");
        }

        private void ClearPursuers()
        {
            foreach (var v in _pursuerVehicles)
            {
                if (v != null && v.Exists())
                    v.Delete();
            }
            _pursuerVehicles.Clear();
            GTA.UI.Notification.Show("~y~Pursuers cleared");
        }

        private void SpeedBoost()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            _missionVehicle.EnginePowerMultiplier = 3.0f;
            _activeTimers.Add(new ActiveTimer
            {
                StartTime = Game.GameTime,
                Duration = 5000,
                Action = () => { if (_missionVehicle != null && _missionVehicle.Exists()) _missionVehicle.EnginePowerMultiplier = 1.0f; }
            });
            GTA.UI.Notification.Show("~y~Speed boost for 5s");
        }

        private void EscortEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_escortVehicles.Count >= 2) return;

            Vector3 spawnPos = _missionVehicle.Position.Around(10f);
            Vector3 streetPos = World.GetNextPositionOnStreet(spawnPos);
            Vehicle escortVehicle = World.CreateRandomVehicle(streetPos, _missionVehicle.Heading);
            if (escortVehicle == null || !escortVehicle.Exists()) return;

            Ped driver = World.CreateRandomPed(escortVehicle.Position);
            if (driver == null || !driver.Exists())
            {
                escortVehicle.Delete();
                return;
            }

            driver.SetIntoVehicle(escortVehicle, VehicleSeat.Driver);
            driver.RelationshipGroup = Game.Player.Character.RelationshipGroup;
            driver.Task.DriveTo(escortVehicle, _missionVehicle, 50f, 30f, DrivingStyle.Normal);

            _escortVehicles.Add(escortVehicle);
            _escortPeds.Add(driver);
            GTA.UI.Notification.Show("~g~Escort arrived");
        }

        private void PunctureEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            var wheels = _missionVehicle.Wheels;
            List<int> candidates = new List<int>();
            for (int i = 0; i < wheels.Count; i++)
            {
                if (!wheels[i].IsBurst) candidates.Add(i);
            }
            if (candidates.Count == 0) return;

            int idx = candidates[new Random().Next(candidates.Count)];
            wheels[idx].Burst();
            GTA.UI.Notification.Show("~r~Tire punctured!");
        }

        private void StallEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            _missionVehicle.IsEngineRunning = false;
            _activeTimers.Add(new ActiveTimer
            {
                StartTime = Game.GameTime,
                Duration = 3000,
                Action = () => { if (_missionVehicle != null && _missionVehicle.Exists()) _missionVehicle.IsEngineRunning = true; }
            });
            GTA.UI.Notification.Show("~r~Engine stalled for 3s");
        }

        private void PursuersEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_pursuerVehicles.Count >= 6) return;

            for (int i = 0; i < 2; i++)
            {
                Vector3 spawnPos = _missionVehicle.Position.Around(30f);
                Vector3 streetPos = World.GetNextPositionOnStreet(spawnPos);
                Vehicle pursuer = World.CreateRandomVehicle(streetPos, _missionVehicle.Heading);
                if (pursuer == null || !pursuer.Exists()) continue;

                Ped driver = World.CreateRandomPed(pursuer.Position);
                if (driver == null || !driver.Exists())
                {
                    pursuer.Delete();
                    continue;
                }
                driver.SetIntoVehicle(pursuer, VehicleSeat.Driver);
                driver.RelationshipGroup = new RelationshipGroup("PURSUER_ENEMY");
                driver.Task.FightAgainst(Game.Player.Character);

                _pursuerVehicles.Add(pursuer);
                if (_pursuerVehicles.Count >= 6) break;
            }
            GTA.UI.Notification.Show("~r~Pursuers deployed");
        }

        private void LowTractionEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            _missionVehicle.TractionOverall = 0.3f;
            _activeTimers.Add(new ActiveTimer
            {
                StartTime = Game.GameTime,
                Duration = 8000,
                Action = () => { if (_missionVehicle != null && _missionVehicle.Exists()) _missionVehicle.TractionOverall = 1.0f; }
            });
            GTA.UI.Notification.Show("~r~Low traction for 8s");
        }

        private void ExplosionEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            Vector3 pos = _missionVehicle.Position + new Vector3(
                (float)(new Random().NextDouble() * 6 - 3),
                (float)(new Random().NextDouble() * 6 - 3),
                0.0f);
            World.AddExplosion(pos, ExplosionType.Grenade, 3.0f, 0.5f, null, true, false);
            if (_missionVehicle.Exists() && _missionVehicle.Health <= 0)
            {
                _missionVehicle.Health = 1;
            }
            GTA.UI.Notification.Show("~r~Explosion near vehicle");
        }

        private void DetourEffect()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists() || _inDetour) return;
            _inDetour = true;
            _originalDestination = _destinationBlip.Position;
            _destinationBlip.Position = World.GetNextPositionOnStreet(_missionVehicle.Position.Around(500f));
            GTA.UI.Notification.Show("~r~Detour! New checkpoint for 30s");
            _activeTimers.Add(new ActiveTimer
            {
                StartTime = Game.GameTime,
                Duration = 30000,
                Action = () =>
                {
                    if (_destinationBlip != null && _destinationBlip.Exists())
                        _destinationBlip.Position = _originalDestination;
                    _inDetour = false;
                    GTA.UI.Notification.Show("~g~Original destination restored");
                }
            });
        }

        // ---------- Tick ----------
        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();

            if (_state != MissionState.Active) return;

            // Check mission vehicle existence and ownership
            if (_missionVehicle == null || !_missionVehicle.Exists())
            {
                MissionFail("Vehicle lost");
                return;
            }

            if (Game.Player.Character.CurrentVehicle != _missionVehicle)
            {
                MissionFail("Vehicle changed");
                return;
            }

            if (_missionVehicle.Health <= 0)
            {
                MissionFail("Vehicle destroyed");
                return;
            }

            // Timer
            if ((DateTime.Now - _missionStartTime).TotalSeconds >= 600)
            {
                MissionFail("Time's up!");
                return;
            }

            // Destination reached
            if (_destinationBlip != null && _destinationBlip.Exists() &&
                Vector3.Distance(_missionVehicle.Position, _destinationBlip.Position) < 10f)
            {
                MissionWin();
                return;
            }

            // Active timers
            int now = Game.GameTime;
            for (int i = _activeTimers.Count - 1; i >= 0; i--)
            {
                ActiveTimer timer = _activeTimers[i];
                if (now - timer.StartTime >= timer.Duration)
                {
                    timer.Action?.Invoke();
                    _activeTimers.RemoveAt(i);
                }
            }
        }

        // ---------- Cleanup ----------
        private void OnAborted(object sender, EventArgs e)
        {
            CleanupMission();
            _client?.Dispose();
        }

        // ---------- Helper Classes ----------
        private class ActiveTimer
        {
            public int StartTime;
            public float Duration; // milliseconds
            public Action Action;
        }
    }
}
